// // This module implements a 8-bit shift register that accepts a single bit input `data_in` and is controlled by a clock signal `clk` and a reset signal `reset`. When the `reset` signal is asserted, the shift register clears to zero. On the rising edge of the clock, if `shift_en` is low, the register shifts its contents to the right, inserting `data_in` into the most significant bit and dropping the least significant bit. The output `data_out` reflects the value of the least significant bit of the shift register.
module top_module(
    input clk,
    input reset,
    input data_in,
    input shift_en,
    output reg data_out
);reg [7:0] shift_reg;

    always @(posedge clk) begin
        if (reset) begin
            shift_reg <= 8'b0;
        end else if (shift_en) begin
            shift_reg <= {shift_reg[6:0], data_in};
        end
    end

    assign data_out = shift_reg[7];

endmodule
